SELECT id, name, score, age, created_at, updated_at
FROM student
WHERE id = #{id}

SELECT id, name, score, age, created_at, updated_at
FROM student
WHERE name = #{name}

SELECT id, name, score, age, created_at, updated_at
FROM student


        AND name LIKE CONCAT('%', #{name}, '%')


        AND score >= #{scoreMin}


        AND score <= #{scoreMax}


        AND age = #{age}


ORDER BY id ASC

SELECT id, name, score, age, created_at, updated_at FROM student WHERE id IN
#{id}
ORDER BY id ASC
